checker_dsl:
EXISTS (`taint source S`, `taint sink K`, `permissions construction P`) {
  AND {
    (`S is an instance of ActiveThreatModelSource`),
    EXISTS (`expression E`) {
      AND {
        (`K is a DataFlow::Node`),
        (`K's associated expression is E`)
      }
    },
    OR {
      EXISTS (`method call MC`) {
        AND {
          (`P is the method call MC`),
          (`P is an instance of PermissionsCheckMethodCall`),
          (`E is the first argument (index 0) of method call MC`)
        }
      },
      EXISTS (`constructor call CC`) {
        AND {
          (`P is the constructor call CC`),
          (`P is an instance of WildCardPermissionConstruction`),
          (`E is the first argument (index 0) of constructor call CC`)
        }
      }
    },
    (`there exists a taint flow path from source S to sink K`)
  }
}
